import { useRef, useEffect } from 'react';

let _activeAudio = null;

export function stopGlobalAudio() {
  if (!_activeAudio) return;
  _activeAudio.pause();
  _activeAudio = null;
}

export function useAudioPlayer({ audioSrc, isActive }) {
  const audioRef = useRef(null);

  // 设置 src
  useEffect(() => {
    const audio = audioRef.current;
    if (!audio) return;
    if (!audioSrc) { audio.removeAttribute('src'); audio.load(); return; }
    audio.src = audioSrc;
    audio.load();
    return () => {
      audio.pause();
      audio.removeAttribute('src');
      audio.load();
      if (_activeAudio === audio) _activeAudio = null;
    };
  }, [audioSrc]);

  // isActive=false 时暂停
  useEffect(() => {
    if (isActive) return;
    const audio = audioRef.current;
    if (audio && _activeAudio === audio) {
      audio.pause();
      _activeAudio = null;
    }
  }, [isActive]);

  return { audioRef };
}
